var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가장 먼저 공략한 대균열은 캄파멘토.","JPN":"最初に攻略した大亀裂はカンパメント。","ENG":"The first Grand Dimension Crevice I went to was in Campamento.","TWN":"最先攻略的大峽谷是坎帕門托。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳은 탐험대로 위장하여 대균열에 접근할 수 있었죠.","JPN":"ここには探検隊として偽装し、大亀裂に接近することができました。","ENG":"I was able to approach the Grand Dimension Crevice by disguising myself as an expedition member.","TWN":"我依靠著偽裝成探險隊接近了那裡。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다음으로는 화보 촬영을 명분으로 방문한 프론트 베이.","JPN":"次は写真集の撮影という名目で訪問したフロントベイ。","ENG":"After, I visited Front Bay under the pretext of a photoshoot.","TWN":"接下來以拍攝畫報為名訪問了前灣。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"해저 깊은 곳에 있는 대균열에 거울 조각을 끼워 넣는 건 쉬운 일이 아니었습니다.","JPN":"海底深く腰掛けている大亀裂に鏡の破片を仕込むのは、決して容易ではありませんでした。","ENG":"It wasn't easy placing a mirror fragment into a Grand Dimension Crevice deep under the sea.","TWN":"將鏡子碎片嵌入深海中的大峽谷並非易事……"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세번째는 그라운드 원.","JPN":"三つ目はグラウンド・ワン。","ENG":"The third was in Ground One.","TWN":"第三個是G1。"},"stage":{"bg":"GROUND_ONE","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"예상치 못한 변수가 발생했지만, 결국 각본대로 대균열에 조각을 끼워둘 수 있었어요.","JPN":"予想外のトラブルが発生しましたが、私の脚本に狂いはありませんでした。無事大亀裂に破片を仕込むことに成功。","ENG":"Although unexpected variables arose, I was ultimately able to place a fragment into the Grand Dimension Crevice, all according to the script.","TWN":"雖然出現了意想不到的變數，但最終還是按照劇本將碎片嵌入了大峽谷。"},"stage":{"bg":"GROUND_ONE","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……챔버.","JPN":"……チェンバー。","ENG":"...Chamber.","TWN":"……強巴."},"stage":{"bg":"CHAMBER","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"수시로 대균열 탐사대가 결성되는 이곳은 비교적 다른 곳보다 수월한 편이었죠.","JPN":"時々大亀裂の探査部隊が結成されるここは、他のところより比較的簡単でした。","ENG":"It was comparatively easier as expedition teams were formed frequently.","TWN":"這裡經常組建大峽谷探險，相對其他地方來說比較輕鬆。"},"stage":{"bg":"CHAMBER","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다섯 번째 대균열은 샤레이드.","JPN":"五つ目の大亀裂はシャレード。","ENG":"The fifth was in Charade.","TWN":"第五是查雷德。"},"stage":{"bg":"CHARADE","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"건틀렛 리그가 진행 중이었던 이곳에 있는 동안에는 꽤 많은 일이 있었답니다.","JPN":"ガントレットリーグが進行中だったこの場所にいる間は、結構多くの出来事がありました。","ENG":"A lot had happened while the Gauntlet League was ongoing.","TWN":"在聖鎧聯賽進行期間，這裡發生了很多事情。"},"stage":{"bg":"CHARADE","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결과적으로는 하베스터의 힘을 빌려, 거울 조각을 끼워 넣었을 수 있었어요.","JPN":"結果的にはハーベスターの力を借りて、鏡の破片を仕込むことができました。","ENG":"In the end, I was able to place a mirror fragment in with the help of Harvester.","TWN":"最終借助收割者的力量，成功嵌入了鏡子碎片。"},"stage":{"bg":"CHARADE","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마지막 로터스의 대균열…….","JPN":"そして最後、ロータスの大亀裂……","ENG":"And the last was Lotus.","TWN":"然後是最後的洛德斯……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 전 세계 여섯 군데의 대균열에 클리파 차원과 연결된 거울 조각을 끼워 넣었습니다.","JPN":"私は全世界、六か所の大亀裂にクリファ次元に繋がる鏡の破片を仕込みました。","ENG":"I have successfully placed a mirror fragment in all six Grand Dimension Crevices around the world that are connected to the Qlipha Dimension.","TWN":"我在全世界六個大峽谷中嵌入了與逆卡巴拉次元相連的鏡片。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"코핀 오브 타기리온의 <color=#ffd34c>마지막 열쇠</color>가 해방된 지금.","JPN":"コフィン・オブ・タギリオンの<color=#ffd34c>最後の鍵</color>が解放された今。","ENG":"And now, with Coffin of Thagirion's <color=#ffd34c>last key</color> being liberated...","TWN":"塔基里翁之棺<color=#ffd34c>最後的鑰匙</color>已經解放。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그림자 전당 내부로부터 방출되는 당신의 클리파 타입 허수 에너지는…….","JPN":"影の殿堂の内部から放出されるあなたのクリファタイプ虚数エネルギーは……","ENG":"Your Qlipha-type Imaginary Energy radiating from within the Shadow Palace...","TWN":"從暗影殿堂內部釋放出的你的神聖虛空能量……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세계 각지의 대균열과 연결된 거울 조각과 공명하여, 전 세계로 확산되겠죠.","JPN":"世界各地の大亀裂と繋がった鏡の破片と共鳴し、全世界へと拡散するでしょう。","ENG":"It will resonate with the mirror fragments linked to the Grand Dimension Crevices around the world and start to spread.","TWN":"將與連接世界各地大峽谷的鏡片共鳴，擴散到全世界。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"암군이여. 계약은 지켰습니다.","JPN":"暗君よ。契約は守りました。","ENG":"Oh, Ignorant Monarch. I have kept my end of the contract.","TWN":"昏君啊。我遵守了契約。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마침내 무대는 클라이맥스에 다다르겠죠.","JPN":"そしてついに舞台はクライマックスを迎えるでしょう。","ENG":"And now, the performance will soon reach its climax.","TWN":"現在，舞台即將迎來高潮。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……그 끝이 비극일지라도.","JPN":"……その終わりが悲劇であっても。","ENG":"...Even if the end will be tragic.","TWN":"……即使它的結局是悲劇。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>로터스, 그림자 전당 내부로부터 특이 에너지 확산 관측.</color>","JPN":"<color=#ffd34c>ロータス、影の殿堂の内部より特異エネルギーの拡散を観測。</color>","ENG":"<color=#ffd34c>In Lotus, detecting abnormal energy spreading from Shadow Palace.</color>","TWN":"<color=#ffd34c>洛德斯，在暗影殿堂內部觀察到特殊的能量擴散。</color>","SCN":"<color=#ffd34c>观测到洛德斯，暗影殿堂内部有奇异的能量扩散。</color>","DEU":"<color=#ffd34c>In Lotus, detecting abnormal energy spreading from Shadow Palace.</color>","FRA":"<color=#ffd34c>In Lotus, detecting abnormal energy spreading from Shadow Palace.</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>분석 결과: 신성 클리파 타입- 타기리온.</color>","JPN":"<color=#ffd34c>分析結果：神聖クリファタイプ-タギリオン。</color>","ENG":"<color=#ffd34c>Analysis results: Divinity Qlipha Type- Thagirion.</color>","TWN":"<color=#ffd34c>分析結果：神聖逆卡巴拉類型-塔基里翁。</color>","SCN":"<color=#ffd34c>分析结果：神圣逆卡巴拉类型-塔基里翁。</color>","DEU":"<color=#ffd34c>Analysis results: Divinity Qlipha Type- Thagirion.</color>","FRA":"<color=#ffd34c>Analysis results: Divinity Qlipha Type- Thagirion.</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>마왕 강림 및 현실 차원계면 붕괴까지… 앞으로 약 30분.</color>","JPN":"L50_1","ENG":"L50_1","TWN":"L50_1","SCN":"L50_1","DEU":"L50_1","FRA":"L50_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};